# Sensitivity analysis: three-scenario ROI
from dataclasses import dataclass

@dataclass
class ScenarioResult:
    name: str
    total_cost_3yr: float
    total_benefit_3yr: float

    @property
    def net_value(self) -> float:
        return self.total_benefit_3yr - self.total_cost_3yr

    @property
    def roi_pct(self) -> float:
        return (self.net_value / self.total_cost_3yr) * 100

    @property
    def payback_months(self) -> float:
        # Approximate: assume linear benefit accrual
        annual_benefit = self.total_benefit_3yr / 3
        annual_cost = self.total_cost_3yr / 3
        if annual_benefit <= annual_cost:
            return float("inf")
        # Simple monthly payback approximation
        monthly_net = (annual_benefit - annual_cost) / 12
        return self.total_cost_3yr / (monthly_net * 12) * 12

scenarios = [
    ScenarioResult("Conservative", total_cost_3yr=5_500_000, total_benefit_3yr=9_200_000),
    ScenarioResult("Base Case",    total_cost_3yr=5_036_000, total_benefit_3yr=13_200_000),
    ScenarioResult("Optimistic",   total_cost_3yr=4_800_000, total_benefit_3yr=18_400_000),
]

print(f"{'Scenario':15} {'Cost 3yr':>12} {'Benefit 3yr':>12} {'Net Value':>12} {'ROI':>8}")
print("-" * 65)
for s in scenarios:
    print(f"{s.name:15} ${s.total_cost_3yr/1e6:>9.1f}M ${s.total_benefit_3yr/1e6:>9.1f}M ${s.net_value/1e6:>9.1f}M {s.roi_pct:>6.0f}%")
# Scenario        Cost 3yr  Benefit 3yr    Net Value      ROI
# -----------------------------------------------------------------
# Conservative     $5.5M       $9.2M        $3.7M     67%
# Base Case        $5.0M      $13.2M        $8.2M    163%
# Optimistic       $4.8M      $18.4M       $13.6M    283%

# Programme reporting: quarterly ROI tracker
from dataclasses import dataclass, field
from datetime import date

@dataclass
class QuarterlyMetrics:
    quarter: str                      # e.g. "2025-Q2"
    budget_ytd: float                 # approved budget spend to date
    actual_spend_ytd: float           # actual spend to date
    active_use_cases: int
    measured_impact_ytd: float        # USD of documented, measured value
    pipeline_use_cases: int           # in intake, not yet live

    @property
    def budget_variance_pct(self) -> float:
        return ((self.actual_spend_ytd - self.budget_ytd) / self.budget_ytd) * 100

    @property
    def roi_ytd(self) -> float:
        if self.actual_spend_ytd == 0:
            return 0.0
        return ((self.measured_impact_ytd - self.actual_spend_ytd) / self.actual_spend_ytd) * 100

    def summary(self) -> str:
        variance_flag = "⚠" if abs(self.budget_variance_pct) > 10 else "✓"
        return (
            f"{self.quarter}: {self.active_use_cases} live use cases | "
            f"Impact: ${self.measured_impact_ytd/1e6:.1f}M | "
            f"Spend: ${self.actual_spend_ytd/1e6:.1f}M {variance_flag} | "
            f"ROI YTD: {self.roi_ytd:.0f}%"
        )

# Example programme progress
quarters = [
    QuarterlyMetrics("2025-Q1", 350_000, 310_000, 0, 0, 5),
    QuarterlyMetrics("2025-Q2", 700_000, 680_000, 2, 180_000, 8),
    QuarterlyMetrics("2025-Q3", 1_100_000, 1_050_000, 4, 620_000, 12),
    QuarterlyMetrics("2025-Q4", 1_500_000, 1_480_000, 6, 1_350_000, 15),
]
for q in quarters:
    print(q.summary())
# 2025-Q1: 0 live use cases | Impact: $0.0M | Spend: $0.3M ✓ | ROI YTD: -100%
